import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What are macros?", a: "Macros are macronutrients: protein, carbohydrates, and fat. They provide calories and shape how your diet supports energy, recovery, and body composition." },
  { q: "How do you calculate macros for weight loss?", a: "Start with estimated daily calories, create a moderate deficit, set protein high enough to preserve muscle, then divide the remaining calories between carbs and fat." },
  { q: "What is IIFYM?", a: "IIFYM means If It Fits Your Macros. It is a flexible dieting approach that focuses on hitting daily protein, carbohydrate, fat, and calorie targets." },
  { q: "How much protein do you need per day?", a: "Many active adults use about 0.7 to 1.0 grams of protein per pound of body weight, depending on goal, training, and body composition." },
  { q: "What is the best macro ratio for muscle gain?", a: "A common muscle gain setup is high protein, moderate to high carbs for training performance, and enough fat for hormones and overall health." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const activityMap: Record<string, number> = { Sedentary: 1.2, Light: 1.375, Moderate: 1.55, Active: 1.725, Athlete: 1.9 };
const macroPresets: Record<string, { protein: number; carbs: number; fat: number }> = {
  Standard: { protein: 0.3, carbs: 0.4, fat: 0.3 },
  "Low carb": { protein: 0.35, carbs: 0.25, fat: 0.4 },
  Keto: { protein: 0.25, carbs: 0.05, fat: 0.7 },
  "High protein": { protein: 0.4, carbs: 0.3, fat: 0.3 },
};
function bmr(gender: string, age: number, heightCm: number, weightKg: number) {
  return 10 * weightKg + 6.25 * heightCm - 5 * age + (gender === "Male" ? 5 : -161);
}

export default function MacroCalculator() {
  const [age, setAge] = useState(30);
  const [gender, setGender] = useState("Male");
  const [height, setHeight] = useState(175);
  const [weight, setWeight] = useState(80);
  const [activity, setActivity] = useState("Moderate");
  const [goal, setGoal] = useState("Maintain");
  const [style, setStyle] = useState("Standard");
  const result = useMemo(() => {
    const maintenance = bmr(gender, age, height, weight) * activityMap[activity];
    const calories = goal === "Lose weight" ? maintenance - 500 : goal === "Gain muscle" ? maintenance + 300 : maintenance;
    const preset = macroPresets[style];
    return { calories, protein: calories * preset.protein / 4, carbs: calories * preset.carbs / 4, fat: calories * preset.fat / 9, preset };
  }, [age, gender, height, weight, activity, goal, style]);
  const rows = [
    ["Weight Loss", "TDEE - 500", "30-40%", "25-35%", "25-35%", "30-40%"],
    ["Maintenance", "TDEE", "25-35%", "35-45%", "25-35%", "25-35%"],
    ["Muscle Gain", "TDEE + 300", "30-35%", "40-50%", "20-30%", "30-35%"],
    ["Keto", "Goal calories", "20-30%", "5-10%", "60-75%", "20-30%"],
    ["Athletic Performance", "TDEE + activity", "20-30%", "45-60%", "20-30%", "20-30%"],
  ];
  return (
    <>
      <SEOHead title="Free Macro Calculator Online - Calculate Daily Protein Carbs and Fat Instantly | CalcHive" description="Free online macro calculator. Calculate your daily protein, carbohydrate and fat targets based on your goal, body stats and activity level instantly. 100% free, no signup required." canonical="/macro-calculator" keywords="free macro calculator, macronutrient calculator free online, IIFYM calculator free, protein carbs fat calculator free, daily macro calculator free online" category="Health Calculators" breadcrumbName="Free Macro Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Macro Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate daily calories, protein, carbs, and fat from your body stats, activity, goal, and diet style.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Age</label><input type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Gender</label><select value={gender} onChange={(e) => setGender(e.target.value)} className={inputClass}><option>Male</option><option>Female</option></select></div><div><label className="text-sm font-semibold block mb-2">Height (cm)</label><input type="number" value={height} onChange={(e) => setHeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Weight (kg)</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Activity level</label><select value={activity} onChange={(e) => setActivity(e.target.value)} className={inputClass}>{Object.keys(activityMap).map((x) => <option key={x}>{x}</option>)}</select></div><div><label className="text-sm font-semibold block mb-2">Goal</label><select value={goal} onChange={(e) => setGoal(e.target.value)} className={inputClass}><option>Lose weight</option><option>Maintain</option><option>Gain muscle</option></select></div><div><label className="text-sm font-semibold block mb-2">Diet style</label><select value={style} onChange={(e) => setStyle(e.target.value)} className={inputClass}>{Object.keys(macroPresets).map((x) => <option key={x}>{x}</option>)}</select></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Daily Calories</p><p className="text-5xl sm:text-6xl font-black text-white">{Math.round(result.calories)}</p></div><div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">{[["Protein", result.protein, result.preset.protein], ["Carbs", result.carbs, result.preset.carbs], ["Fat", result.fat, result.preset.fat]].map(([label, grams, pct]) => <div key={String(label)} className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">{label}</p><p className="text-lg font-extrabold">{Math.round(Number(grams))} g</p><p className="text-xs text-muted-foreground">{Math.round(Number(pct) * 100)}%</p></div>)}</div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your Daily Macros for Free</h2><p className="text-muted-foreground leading-relaxed">Estimate daily calories from BMR and activity, adjust for your goal, then split calories into protein, carbs, and fat using the selected diet preset.</p><h2 className="text-2xl font-bold">How to Set Macros for Weight Loss Muscle Gain and Maintenance</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Recommended Daily Macros by Goal</caption><thead className="bg-muted/60"><tr>{["Goal", "Calories", "Protein", "Carbs", "Fat", "Protein %"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={r[0]}>{r.map((c) => <td key={c} className="py-2.5 px-3">{c}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free IIFYM Macro Calculator for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/macro-calculator" headingLevel="h3" /></main>
    </>
  );
}


